import groovy.json.JsonOutput
import java.net.URL
import java.net.HttpURLConnection

def oid = ''
def nombre = 'Agente'
def correo = ''
def u = event.requestee?.resolveObjectType()
if (u != null) {
    oid = u.getOid() ?: ''
    if (u.getName() != null) nombre = u.getName().getOrig()
    if (u.getFullName() != null) nombre = u.getFullName().getOrig()
    if (u.getEmailAddress() != null) correo = u.getEmailAddress()
}
def cuerpo = JsonOutput.toJson([ oid: oid, nombre: nombre, correo: correo ])

def url = new URL('http://telesecure_webhook:5000/provision')
def conn = (HttpURLConnection) url.openConnection()
conn.setRequestMethod('POST')
conn.setConnectTimeout(10000)
conn.setReadTimeout(120000)
conn.setDoOutput(true)
conn.setRequestProperty('Content-Type', 'application/json')
conn.setRequestProperty('X-Auth-Token', 'e228111abf729700c4934bc2b7e36701b5fc8859419619a5')
conn.getOutputStream().withWriter('UTF-8') { it.write(cuerpo) }
def codigo = conn.getResponseCode()
def stream = (codigo >= 400) ? conn.getErrorStream() : conn.getInputStream()
def respuesta = stream?.getText('UTF-8') ?: ''
conn.disconnect()
if (codigo >= 400) {
    throw new RuntimeException('Webhook error HTTP ' + codigo + ': ' + respuesta)
}
